#!/usr/bin/env python3
"""Apply mechanical ruff fixes from /tmp/ruff.json."""

from __future__ import annotations

import json
import re
from collections import defaultdict
from pathlib import Path

RUFF_JSON = Path("/tmp/ruff.json")
ROOT = Path("/workspaces/agno")


def load_violations() -> list[dict]:
    with RUFF_JSON.open() as f:
        return json.load(f)


def param_from_message(message: str) -> str | None:
    m = re.search(r"`(\w+)`", message)
    return m.group(1) if m else None


def fix_arg_in_file(path: Path, line_params: dict[int, set[str]]) -> bool:
    lines = path.read_text().splitlines(keepends=True)
    changed = False
    for row, params in sorted(line_params.items()):
        idx = row - 1
        if idx < 0 or idx >= len(lines):
            continue
        line = lines[idx]
        new_line = line
        for param in sorted(params, key=len, reverse=True):
            if param.startswith("_"):
                continue
            replacement = f"_{param}"
            new_line, n = re.subn(rf"\b{re.escape(param)}\b", replacement, new_line)
            if n:
                changed = True
        lines[idx] = new_line
    if changed:
        path.write_text("".join(lines))
    return changed


def fix_ruf001(path: Path, row: int) -> bool:
    lines = path.read_text().splitlines(keepends=True)
    idx = row - 1
    if "–" not in lines[idx]:
        return False
    lines[idx] = lines[idx].replace("–", "-")
    path.write_text("".join(lines))
    return True


def fix_ble001(path: Path, row: int) -> bool:
    lines = path.read_text().splitlines(keepends=True)
    idx = row - 1
    line = lines[idx]
    if "noqa: BLE001" in line:
        return False
    stripped = line.rstrip()
    if stripped.endswith(":"):
        # except Exception as exc: or except Exception:
        comment = "  # noqa: BLE001  # workflow/step error boundary"
    else:
        comment = "  # noqa: BLE001"
    if "#" in stripped:
        return False
    lines[idx] = stripped + comment + ("\n" if line.endswith("\n") else "")
    path.write_text("".join(lines))
    return True


def fix_plc0415(path: Path, row: int) -> bool:
    lines = path.read_text().splitlines(keepends=True)
    idx = row - 1
    line = lines[idx]
    if "noqa: PLC0415" in line:
        return False
    stripped = line.rstrip()
    indent = line[: len(line) - len(line.lstrip())]
    if stripped.endswith(")"):
        # import inside call - add on closing part
        lines[idx] = stripped + "  # noqa: PLC0415  # lazy import" + ("\n" if line.endswith("\n") else "")
    else:
        lines[idx] = stripped + "  # noqa: PLC0415  # lazy/circular import" + (
            "\n" if line.endswith("\n") else ""
        )
    path.write_text("".join(lines))
    return True


def main() -> None:
    violations = load_violations()
    arg_by_file: dict[str, dict[int, set[str]]] = defaultdict(lambda: defaultdict(set))

    for v in violations:
        code = v["code"]
        path = Path(v["filename"])
        row = v["location"]["row"]
        if code in ("ARG001", "ARG002", "ARG005"):
            p = param_from_message(v["message"])
            if p:
                arg_by_file[str(path)][row].add(p)

    for fpath, line_params in arg_by_file.items():
        fix_arg_in_file(Path(fpath), line_params)

    for v in violations:
        code = v["code"]
        path = Path(v["filename"])
        row = v["location"]["row"]
        if code == "RUF001":
            fix_ruf001(path, row)
        elif code == "BLE001":
            fix_ble001(path, row)
        elif code == "PLC0415":
            fix_plc0415(path, row)


if __name__ == "__main__":
    main()

