#!/usr/bin/env python3
"""Add BLE001 noqa with comments on workflow error boundaries."""

import json
import re
from pathlib import Path

ROOT = Path("/workspaces/agno")
JSON = Path("/tmp/ruff2.json")

BLE_COMMENTS = {
    "workflow": "workflow step error boundary",
    "step": "workflow step error boundary",
    "runner": "runner entrypoint error boundary",
    "prompt": "Langfuse fetch fallback",
    "session": "DB lookup failure returns JSON error",
    "streaming": "parse/followup fallback",
    "discovery": "tool/workflow error boundary",
    "validity": "best-effort cleanup or nested failure",
    "notify": "notification delivery fallback",
    "project_board": "poll step error boundary",
    "synapse_mock": "demo workflow error boundary",
    "compose": "best-effort atexit HTTP client cleanup",
}


def ble_comment(path: str) -> str:
    p = path.lower()
    for key, msg in BLE_COMMENTS.items():
        if key.replace("_", "") in p.replace("_", "").replace("/", ""):
            return msg
    if "workflow" in p:
        return "workflow step error boundary"
    if "tools" in p:
        return "tool error boundary"
    return "intentional catch-all error boundary"


def fix_ble(path: Path, row: int) -> None:
    lines = path.read_text().splitlines(keepends=True)
    idx = row - 1
    line = lines[idx]
    if "noqa: BLE001" in line:
        return
    stripped = line.rstrip("\n")
    if "except Exception" not in stripped:
        return
    comment = f"  # noqa: BLE001  # {ble_comment(str(path))}"
    if "# noqa" in stripped:
        # append BLE001 to existing noqa
        stripped = re.sub(
            r"# noqa: ([^\s#]+)",
            lambda m: f"# noqa: {m.group(1)}, BLE001"
            if "BLE001" not in m.group(1)
            else m.group(0),
            stripped,
            count=1,
        )
        if "BLE001" not in stripped:
            stripped += "  # BLE001 intentional catch-all"
    else:
        stripped += comment
    lines[idx] = stripped + ("\n" if line.endswith("\n") else "")
    path.write_text("".join(lines))


def fix_plc(path: Path, row: int) -> None:
    lines = path.read_text().splitlines(keepends=True)
    idx = row - 1
    line = lines[idx]
    if "noqa: PLC0415" in line:
        return
    stripped = line.rstrip("\n")
    if not stripped.lstrip().startswith("import ") and " import " not in stripped:
        return
    comment = "  # noqa: PLC0415  # lazy/circular import"
    if "test" in str(path):
        comment = "  # noqa: PLC0415  # import after env patch"
    lines[idx] = stripped + comment + ("\n" if line.endswith("\n") else "")
    path.write_text("".join(lines))


def main() -> None:
    with JSON.open() as f:
        data = json.load(f)
    for v in data:
        path = Path(v["filename"])
        row = v["location"]["row"]
        if v["code"] == "BLE001":
            fix_ble(path, row)
        elif v["code"] == "PLC0415":
            fix_plc(path, row)


if __name__ == "__main__":
    main()

